// Theme colors for light and dark mode
export const lightTheme = {
  background: '#F9FAFB',
  card: '#FFFFFF',
  text: '#1F2937',
  subText: '#6B7280',
  border: '#E5E7EB',
  primary: '#4F46E5',
  secondary: '#10B981',
  accent: '#F59E0B',
  danger: '#EF4444',
  success: '#10B981',
  warning: '#F59E0B',
  info: '#3B82F6',
};

export const darkTheme = {
  background: '#111827',
  card: '#1F2937',
  text: '#F9FAFB',
  subText: '#9CA3AF',
  border: '#374151',
  primary: '#6366F1',
  secondary: '#34D399',
  accent: '#FBBF24',
  danger: '#F87171',
  success: '#34D399',
  warning: '#FBBF24',
  info: '#60A5FA',
};

export type Theme = typeof lightTheme;

// Helper function to get theme based on dark mode state
export const getTheme = (isDarkMode: boolean): Theme => {
  return isDarkMode ? darkTheme : lightTheme;
};
